import subprocess, json, threading, sys

def content_length_frame(data: bytes) -> bytes:
    return b'Content-Length: ' + str(len(data)).encode() + b'\r\n\r\n' + data

def read_message(stream) -> dict:
    headers = {}
    while True:
        line = stream.readline().decode().strip()
        if not line:
            break
        key, _, val = line.partition(': ')
        headers[key] = val
    length = int(headers['Content-Length'])
    body = stream.read(length)
    return json.loads(body)

def send_message(stream, msg: dict):
    data = json.dumps(msg).encode()
    stream.write(content_length_frame(data))
    stream.flush()

# Launch pyright language server
proc = subprocess.Popen(
    ['pyright-langserver', '--stdio'],
    stdin=subprocess.PIPE,
    stdout=subprocess.PIPE,
)

# Step 1: send initialize request
send_message(proc.stdin, {
    'jsonrpc': '2.0', 'id': 1,
    'method': 'initialize',
    'params': {
        'processId': None,
        'rootUri': 'file:///workspace',
        'capabilities': {
            'textDocument': {
                'hover': {'contentFormat': ['plaintext']},
                'definition': {},
                'publishDiagnostics': {},
            }
        },
    },
})

resp = read_message(proc.stdout)   # receive InitializeResult
print('Server capabilities:', list(resp['result']['capabilities'].keys()))

# Step 2: notify initialized
send_message(proc.stdin, {'jsonrpc': '2.0', 'method': 'initialized', 'params': {}})

# Step 3: open a document
source = 'def greet(name: str) -> str:\n    return "hello " + name\n'
send_message(proc.stdin, {
    'jsonrpc': '2.0', 'method': 'textDocument/didOpen',
    'params': {
        'textDocument': {
            'uri': 'file:///workspace/hello.py',
            'languageId': 'python',
            'version': 1,
            'text': source,
        }
    },
})

# Step 4: hover at line 1, character 4 (over 'greet')
send_message(proc.stdin, {
    'jsonrpc': '2.0', 'id': 2,
    'method': 'textDocument/hover',
    'params': {
        'textDocument': {'uri': 'file:///workspace/hello.py'},
        'position': {'line': 0, 'character': 4},
    },
})

msg = read_message(proc.stdout)
print('Hover result:', msg)

# Shutdown
send_message(proc.stdin, {'jsonrpc': '2.0', 'id': 99, 'method': 'shutdown', 'params': None})
read_message(proc.stdout)
send_message(proc.stdin, {'jsonrpc': '2.0', 'method': 'exit', 'params': None})
proc.wait()

# Integrating LSP queries as agent tools (OpenAI-style function calling)
import json
from dataclasses import dataclass
from typing import Any
from multilspy import SyncLanguageServer
from multilspy.multilspy_config import MultilspyConfig
from multilspy.multilspy_logger import MultilspyLogger

@dataclass
class LSPToolkit:
    lsp: SyncLanguageServer

    def hover(self, file: str, line: int, character: int) -> str:
        result = self.lsp.request_hover(file, line, character)
        if not result:
            return '(no hover information)'
        contents = result.get('contents', {})
        if isinstance(contents, dict):
            return contents.get('value', '')
        return str(contents)

    def go_to_definition(self, file: str, line: int, character: int) -> list[dict]:
        defs = self.lsp.request_definition(file, line, character)
        return [{
            'file': d['uri'].replace('file://', ''),
            'line': d['range']['start']['line'],
            'col': d['range']['start']['character'],
        } for d in defs]

    def find_references(self, file: str, line: int, character: int) -> list[dict]:
        refs = self.lsp.request_references(file, line, character)
        return [{
            'file': r['uri'].replace('file://', ''),
            'line': r['range']['start']['line'],
        } for r in refs]

    def completions(self, file: str, line: int, character: int) -> list[str]:
        items = self.lsp.request_completions(file, line, character)
        return [i['label'] for i in items[:20]]

    def dispatch(self, tool_name: str, args: dict) -> Any:
        dispatch_map = {
            'hover': self.hover,
            'go_to_definition': self.go_to_definition,
            'find_references': self.find_references,
            'completions': self.completions,
        }
        fn = dispatch_map.get(tool_name)
        if not fn:
            raise ValueError(f'Unknown LSP tool: {tool_name}')
        return fn(**args)

# Usage in an agent loop:
config = MultilspyConfig.from_dict({'code_language': 'python'})
logger = MultilspyLogger()
with SyncLanguageServer.create(config, logger, '/workspace/project') as lsp:
    toolkit = LSPToolkit(lsp)
    # Agent calls tool in response to LLM request
    result = toolkit.dispatch('hover', {'file': 'src/app.py', 'line': 10, 'character': 8})
    print(result)
